from fastapi import APIRouter

router = APIRouter(prefix="/models")

@router.get("/")
def get_models():
    return {
        "models": [
            "RandomForestClassifier",
            "SVC",
            "LogisticRegression",
            "RandomForestRegressor",
            "LinearRegression"
        ]
    }

/* ── Model metadata ─────────────────────────── */
const MODEL_METRICS = {
  RandomForestClassifier: ["accuracy", "f1", "precision", "recall"],
  SVC: ["accuracy", "f1", "precision", "recall"],
  LogisticRegression: ["accuracy", "f1", "precision", "recall"],
  RandomForestRegressor: ["r2", "neg_mean_squared_error"],
  LinearRegression: ["r2", "neg_mean_squared_error"],
};
const MODEL_PARAMS = {
  RandomForestClassifier: [
    "n_estimators",
    "max_depth",
    "min_samples_split",
    "min_samples_leaf",
    "max_features",
    "bootstrap",
    "criterion",
  ],
  RandomForestRegressor: [
    "n_estimators",
    "max_depth",
    "min_samples_split",
    "min_samples_leaf",
    "max_features",
    "bootstrap",
    "criterion",
  ],
  SVC: ["C", "kernel", "degree", "gamma", "coef0", "shrinking"],
  LogisticRegression: [
    "C",
    "solver",
    "penalty",
    "max_iter",
    "fit_intercept",
    "class_weight",
  ],
  LinearRegression: ["fit_intercept", "copy_X", "positive"],
};
const PARAM_HINTS = {
  n_estimators: "example: 50,100,200",
  max_depth: "example: 5,10,20 or null",
  min_samples_split: "example: 2,5,10",
  min_samples_leaf: "example: 1,2,4",
  max_features: "options: sqrt,log2 or number",
  bootstrap: "options: true,false",
  criterion:
    "classifier: gini,entropy | regressor: squared_error,absolute_error",
  C: "example: 0.01,0.1,1,10",
  kernel: "options: linear,rbf,poly,sigmoid",
  degree: "example: 2,3,4 (poly kernel)",
  gamma: "options: scale,auto or 0.1",
  coef0: "example: 0,0.1,0.5",
  shrinking: "options: true,false",
  solver: "options: lbfgs,liblinear,newton-cg,saga",
  penalty: "options: l1,l2,elasticnet,none",
  max_iter: "example: 100,200,500",
  fit_intercept: "options: true,false",
  class_weight: "options: balanced or none",
  copy_X: "options: true,false",
  positive: "options: true,false",
};

/* ── Loader ─────────────────────────────────── */
window.addEventListener("load", () => {
  setTimeout(() => {
    const loader = document.getElementById("loader");
    if (loader) loader.classList.add("hidden");
  }, 1800);
});

/* ── Particle canvas ────────────────────────── */
(function initParticles() {
  const canvas = document.getElementById("particles");
  if (!canvas) return;
  const ctx = canvas.getContext("2d");
  let W, H;

  const isMobile = () => window.innerWidth < 600;

  function resize() {
    W = canvas.width = window.innerWidth;
    H = canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener("resize", resize);

  const COUNT = isMobile() ? 30 : 60;
  const pts = Array.from({ length: COUNT }, () => ({
    x: Math.random() * window.innerWidth,
    y: Math.random() * window.innerHeight,
    vx: (Math.random() - 0.5) * 0.3,
    vy: (Math.random() - 0.5) * 0.3,
    r: Math.random() * 1.3 + 0.4,
  }));

  function draw() {
    ctx.clearRect(0, 0, W, H);
    const linkDist = isMobile() ? 100 : 140;

    for (let i = 0; i < pts.length; i++) {
      for (let j = i + 1; j < pts.length; j++) {
        const dx = pts[i].x - pts[j].x,
          dy = pts[i].y - pts[j].y;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < linkDist) {
          ctx.beginPath();
          ctx.moveTo(pts[i].x, pts[i].y);
          ctx.lineTo(pts[j].x, pts[j].y);
          ctx.strokeStyle = `rgba(200,255,0,${0.12 * (1 - d / linkDist)})`;
          ctx.lineWidth = 0.5;
          ctx.stroke();
        }
      }
    }
    pts.forEach((p) => {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(200,255,0,0.35)";
      ctx.fill();
      p.x += p.vx;
      p.y += p.vy;
      if (p.x < 0) p.x = W;
      if (p.x > W) p.x = 0;
      if (p.y < 0) p.y = H;
      if (p.y > H) p.y = 0;
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

/* ── Toast ──────────────────────────────────── */
function toast(msg, type = "ok") {
  const el = document.getElementById("toast");
  el.textContent = msg;
  el.className = `toast ${type} show`;
  clearTimeout(el._t);
  el._t = setTimeout(() => {
    el.className = "toast";
  }, 3000);
}

/* ── Status ─────────────────────────────────── */
function setStatus(state, label) {
  const dot = document.getElementById("status-dot");
  const text = document.getElementById("status-text");
  if (!dot || !text) return;
  text.textContent = label;
  const map = {
    ready: ["#c8ff00", "0 0 10px rgba(200,255,0,.6)"],
    running: ["#facc15", "0 0 10px rgba(250,204,21,.6)"],
    done: ["#00e5ff", "0 0 10px rgba(0,229,255,.6)"],
    error: ["#ff3c3c", "0 0 10px rgba(255,60,60,.6)"],
  };
  const [bg, sh] = map[state] || map.ready;
  dot.style.background = bg;
  dot.style.boxShadow = sh;
}

/* ── Stepper ─────────────────────────────────── */
function setStep(n) {
  document.querySelectorAll(".step").forEach((s) => {
    const num = +s.dataset.step;
    s.classList.remove("active", "done");
    if (num === n) s.classList.add("active");
    else if (num < n) s.classList.add("done");
  });
}

/* ── updateOptions ──────────────────────────── */
function updateOptions() {
  const model = document.getElementById("model").value;
  const ms = document.getElementById("metric");
  ms.innerHTML = "";
  MODEL_METRICS[model].forEach((m) => {
    const o = document.createElement("option");
    o.value = m;
    o.text = m;
    ms.appendChild(o);
  });
  document.getElementById("params-container").innerHTML = "";
  addParam();
}

/* ── addParam ───────────────────────────────── */
function addParam() {
  const model = document.getElementById("model").value;
  const cont = document.getElementById("params-container");
  const row = document.createElement("div");
  row.className = "param-row";

  const sw = document.createElement("div");
  sw.className = "select-wrap";
  const sel = document.createElement("select");
  MODEL_PARAMS[model].forEach((p) => {
    const o = document.createElement("option");
    o.value = p;
    o.text = p;
    sel.appendChild(o);
  });
  const chev = document.createElementNS("http://www.w3.org/2000/svg", "svg");
  chev.setAttribute("viewBox", "0 0 24 24");
  chev.setAttribute("fill", "none");
  chev.setAttribute("stroke", "currentColor");
  chev.setAttribute("stroke-width", "2");
  chev.setAttribute("stroke-linecap", "round");
  chev.classList.add("select-chevron");
  const poly = document.createElementNS(
    "http://www.w3.org/2000/svg",
    "polyline",
  );
  poly.setAttribute("points", "6 9 12 15 18 9");
  chev.appendChild(poly);
  sw.append(sel, chev);

  const inp = document.createElement("input");
  inp.type = "text";
  inp.placeholder = PARAM_HINTS[sel.value] || "comma separated values";
  sel.onchange = () => {
    inp.placeholder = PARAM_HINTS[sel.value] || "comma separated values";
  };

  const rm = document.createElement("button");
  rm.innerHTML = "&times;";
  rm.className = "btn-remove";
  rm.onclick = () => row.remove();

  row.append(sw, inp, rm);
  cont.appendChild(row);
}

/* ── buildParamGrid ─────────────────────────── */
function buildParamGrid() {
  const grid = {};
  document.querySelectorAll(".param-row").forEach((row) => {
    const param = row.querySelector("select").value;
    const values = row
      .querySelector("input")
      .value.split(",")
      .map((v) => v.trim())
      .filter(Boolean)
      .map((v) =>
        v === "true" ? true : v === "false" ? false : isNaN(v) ? v : Number(v),
      );
    if (values.length) grid[param] = values;
  });
  return grid;
}

/* ── uploadDataset ──────────────────────────── */
async function uploadDataset() {
  const file = document.getElementById("dataset").files[0];
  if (!file) {
    toast("select a file first", "err");
    return;
  }
  const fd = new FormData();
  fd.append("file", file);
  try {
    await fetch("https://lazytune.onrender.com/datasets/upload", {
      method: "POST",
      body: fd,
    });
    toast("dataset uploaded");
    setStep(2);
  } catch {
    toast("upload failed", "err");
  }
}

/* ── runOptimization ────────────────────────── */
async function runOptimization() {
  const model = document.getElementById("model").value;
  const target = document.getElementById("target").value;
  const metric = document.getElementById("metric").value;
  const param_grid = buildParamGrid();
  const result = document.getElementById("result");
  result.textContent = "Running optimization...";
  result.style.color = "#555";
  setStatus("running", "Running...");
  setStep(4);
  try {
    const res = await fetch("https://lazytune.onrender.com/optimize/", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ model, target, metric, param_grid }),
    });
    const data = await res.json();
    result.textContent = JSON.stringify(data, null, 2);
    result.style.color = "var(--accent)";
    document.getElementById("btn-copy").style.display = "inline-flex";
    toast("optimization complete");
    setStatus("done", "Done");
    document
      .getElementById("section-results")
      .scrollIntoView({ behavior: "smooth" });
  } catch {
    result.textContent = "Backend error — is the server running?";
    result.style.color = "var(--danger)";
    toast("optimization failed", "err");
    setStatus("error", "Error");
  }
}

/* ── copyResult ─────────────────────────────── */
function copyResult() {
  navigator.clipboard.writeText(document.getElementById("result").textContent);
  toast("copied to clipboard");
}

/* ── DOMContentLoaded ───────────────────────── */
document.addEventListener("DOMContentLoaded", () => {
  updateOptions();

  // file label
  const inp = document.getElementById("dataset");
  const lbl = document.getElementById("file-label");
  if (inp && lbl) {
    inp.addEventListener("change", () => {
      lbl.textContent = inp.files[0] ? inp.files[0].name : "No file chosen";
    });
  }

  // drag & drop on upload zone
  const zone = document.getElementById("upload-zone");
  if (zone) {
    zone.addEventListener("dragover", (e) => {
      e.preventDefault();
      zone.style.borderColor = "var(--accent)";
    });
    zone.addEventListener("dragleave", () => {
      zone.style.borderColor = "";
    });
    zone.addEventListener("drop", (e) => {
      e.preventDefault();
      zone.style.borderColor = "";
      const f = e.dataTransfer.files[0];
      if (f && lbl) {
        const dt = new DataTransfer();
        dt.items.add(f);
        inp.files = dt.files;
        lbl.textContent = f.name;
      }
    });
  }

  // stepper nav
  const sectionMap = { 1: "dataset", 2: "model", 3: "params", 4: "results" };
  document.querySelectorAll(".step").forEach((s) => {
    s.addEventListener("click", () => {
      const n = +s.dataset.step;
      setStep(n);
      const el = document.getElementById("section-" + sectionMap[n]);
      if (el) el.scrollIntoView({ behavior: "smooth" });
    });
  });
});

/* ─── TOKENS ──────────────────────────────────────── */
:root {
  --bg: #0a0a0a;
  --surface: #111111;
  --card: #161616;
  --border: #2a2a2a;
  --accent: #c8ff00;
  --accent2: #00e5ff;
  --danger: #ff3c3c;
  --text: #f0f0f0;
  --muted: #666;
  --mono: "Fira Code", monospace;
  --display: "Bebas Neue", sans-serif;
  --body: "DM Sans", sans-serif;
  --r: 8px;
  --max-w: 960px;
  --px: 40px;
}

/* ─── RESET ───────────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}
html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}
body {
  font-family: var(--body);
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
  cursor: crosshair;
  font-size: 16px;
}

/* ─── LOADER ──────────────────────────────────────── */
#loader {
  position: fixed;
  inset: 0;
  z-index: 99999;
  background: var(--bg);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 28px;
  transition:
    opacity 0.5s ease,
    visibility 0.5s ease;
}
#loader.hidden {
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
}

.loader-hex {
  width: 80px;
  height: 80px;
  animation: loaderSpin 2s linear infinite;
  filter: drop-shadow(0 0 18px var(--accent));
}
.loader-hex .lhex {
  fill: var(--accent);
}
.loader-hex .lbolt {
  fill: #0a0a0a;
}

@keyframes loaderSpin {
  0% {
    transform: rotate(0deg) scale(1);
    filter: drop-shadow(0 0 8px var(--accent));
  }
  25% {
    transform: rotate(90deg) scale(1.08);
    filter: drop-shadow(0 0 22px var(--accent));
  }
  50% {
    transform: rotate(180deg) scale(1);
    filter: drop-shadow(0 0 8px var(--accent));
  }
  75% {
    transform: rotate(270deg) scale(1.08);
    filter: drop-shadow(0 0 22px var(--accent));
  }
  100% {
    transform: rotate(360deg) scale(1);
    filter: drop-shadow(0 0 8px var(--accent));
  }
}

.loader-bar-wrap {
  width: 200px;
  height: 2px;
  background: var(--border);
  border-radius: 99px;
  overflow: hidden;
}
.loader-bar {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, var(--accent), var(--accent2));
  border-radius: 99px;
  animation: loadFill 1.6s ease forwards;
  box-shadow: 0 0 10px var(--accent);
}
@keyframes loadFill {
  to {
    width: 100%;
  }
}

.loader-label {
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--muted);
  animation: loaderFade 1.6s ease-in-out infinite alternate;
}
@keyframes loaderFade {
  from {
    opacity: 0.4;
  }
  to {
    opacity: 1;
  }
}

/* ─── SCANLINE ────────────────────────────────────── */
body::after {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 9998;
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(0, 0, 0, 0.13) 2px,
    rgba(0, 0, 0, 0.13) 4px
  );
  pointer-events: none;
  mix-blend-mode: multiply;
}

/* ─── CANVAS ──────────────────────────────────────── */
#particles {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
}

/* ─── HEADER ──────────────────────────────────────── */
header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(10, 10, 10, 0.93);
  border-bottom: 1px solid var(--border);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}
.header-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 14px var(--px);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

/* BRAND */
.brand {
  display: flex;
  align-items: center;
  gap: 13px;
  text-decoration: none;
  flex-shrink: 0;
}
.logo-hex {
  width: 42px;
  height: 42px;
  flex-shrink: 0;
}
.logo-hex svg {
  width: 42px;
  height: 42px;
}
.hex-bg {
  fill: var(--accent);
  animation: hexPulse 3s ease-in-out infinite;
}
.hex-bolt {
  fill: #0a0a0a;
}
@keyframes hexPulse {
  0%,
  100% {
    filter: drop-shadow(0 0 4px var(--accent));
  }
  50% {
    filter: drop-shadow(0 0 16px var(--accent))
      drop-shadow(0 0 32px rgba(200, 255, 0, 0.4));
  }
}

.brand-name {
  font-family: var(--display);
  font-size: 28px;
  letter-spacing: 0.06em;
  color: var(--accent);
  line-height: 1;
}
.brand-tagline {
  font-family: var(--mono);
  font-size: 9px;
  color: var(--muted);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  margin-top: 3px;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 10px;
}
.header-nav {
  display: flex;
  align-items: center;
  gap: 6px;
}
.nav-link {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--muted);
  text-decoration: none;
  padding: 7px 14px;
  border: 1px solid transparent;
  border-radius: var(--r);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  transition: all 0.2s;
  white-space: nowrap;
}
.nav-link:hover {
  color: var(--accent);
  border-color: var(--border);
}
.nav-link.active {
  color: var(--bg);
  background: var(--accent);
  border-color: var(--accent);
}

.status-chip {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 7px 14px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 99px;
  font-family: var(--mono);
  font-size: 11px;
  color: var(--muted);
  letter-spacing: 0.06em;
  white-space: nowrap;
}
.status-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 8px var(--accent);
  animation: blink 2s ease-in-out infinite;
}
@keyframes blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

/* ─── STEPPER ─────────────────────────────────────── */
.stepper-wrap {
  position: relative;
  z-index: 1;
  max-width: var(--max-w);
  margin: 32px auto 0;
  padding: 0 var(--px);
}
.stepper {
  display: flex;
  align-items: center;
}
.step {
  display: flex;
  align-items: center;
  gap: 10px;
  font-family: var(--mono);
  font-size: 12px;
  color: var(--muted);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  cursor: pointer;
  transition: color 0.3s;
}
.step span {
  display: inline;
}
.step.active {
  color: var(--accent);
}
.step.done {
  color: var(--accent2);
}
.step-bubble {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1.5px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 700;
  font-family: var(--mono);
  transition: all 0.3s;
  flex-shrink: 0;
}
.step.active .step-bubble {
  border-color: var(--accent);
  background: var(--accent);
  color: var(--bg);
  box-shadow: 0 0 16px rgba(200, 255, 0, 0.4);
}
.step.done .step-bubble {
  border-color: var(--accent2);
  background: rgba(0, 229, 255, 0.12);
  color: var(--accent2);
}
.step-line {
  flex: 1;
  height: 1px;
  background: var(--border);
  margin: 0 10px;
  position: relative;
  overflow: hidden;
}
.step-line::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, var(--accent), transparent);
  animation: lineScan 3s linear infinite;
}
@keyframes lineScan {
  to {
    left: 200%;
  }
}

/* ─── MAIN ────────────────────────────────────────── */
main {
  position: relative;
  z-index: 1;
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 28px var(--px) 100px;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

/* ─── CARD ────────────────────────────────────────── */
.card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 36px 40px;
  position: relative;
  overflow: hidden;
  transition:
    border-color 0.3s,
    box-shadow 0.3s;
  animation: riseIn 0.5s cubic-bezier(0.22, 0.68, 0, 1.2) both;
}
.card:nth-child(1) {
  animation-delay: 0.05s;
}
.card:nth-child(2) {
  animation-delay: 0.12s;
}
.card:nth-child(3) {
  animation-delay: 0.19s;
}
.card:nth-child(4) {
  animation-delay: 0.26s;
}
@keyframes riseIn {
  from {
    opacity: 0;
    transform: translateY(24px) scale(0.98);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}
.card:hover {
  border-color: rgba(200, 255, 0, 0.2);
  box-shadow:
    0 0 40px rgba(200, 255, 0, 0.05),
    0 8px 40px rgba(0, 0, 0, 0.4);
}
.card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 70px;
  height: 70px;
  background: linear-gradient(135deg, rgba(200, 255, 0, 0.1), transparent);
  border-radius: 14px 0 70px 0;
  opacity: 0;
  transition: opacity 0.3s;
}
.card:hover::before {
  opacity: 1;
}

.card-label {
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--accent);
  margin-bottom: 10px;
  opacity: 0.7;
}
.card h2 {
  font-family: var(--display);
  font-size: 38px;
  letter-spacing: 0.04em;
  margin-bottom: 8px;
  color: var(--text);
}
.card-desc {
  font-size: 14px;
  color: var(--muted);
  margin-bottom: 28px;
  line-height: 1.7;
  font-family: var(--mono);
}

/* ─── UPLOAD ZONE ─────────────────────────────────── */
#upload-zone {
  border: 1.5px dashed var(--border);
  border-radius: 12px;
  padding: 44px 24px;
  text-align: center;
  cursor: pointer;
  background: rgba(255, 255, 255, 0.02);
  transition: all 0.25s;
  margin-bottom: 20px;
  position: relative;
  overflow: hidden;
}
#upload-zone::before {
  content: "";
  position: absolute;
  inset: 0;
  background: radial-gradient(
    ellipse at 50% 120%,
    rgba(200, 255, 0, 0.07),
    transparent 70%
  );
  opacity: 0;
  transition: opacity 0.3s;
}
#upload-zone:hover {
  border-color: var(--accent);
  background: rgba(200, 255, 0, 0.03);
}
#upload-zone:hover::before {
  opacity: 1;
}

.upload-icon-wrap {
  width: 60px;
  height: 60px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  margin: 0 auto 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
  transition:
    transform 0.3s,
    box-shadow 0.3s;
}
#upload-zone:hover .upload-icon-wrap {
  transform: translateY(-4px);
  box-shadow: 0 8px 20px rgba(200, 255, 0, 0.2);
}
.upload-icon-wrap svg {
  width: 26px;
  height: 26px;
}
.upload-text {
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 6px;
}
.upload-filename {
  font-family: var(--mono);
  font-size: 12px;
  color: var(--accent);
  min-height: 18px;
}

/* ─── FIELDS ──────────────────────────────────────── */
.fields-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}
.fields-grid .field:last-child {
  grid-column: 1 / -1;
}

.field-label {
  display: block;
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 9px;
}
input[type="text"],
select {
  width: 100%;
  padding: 13px 16px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r);
  color: var(--text);
  font-family: var(--mono);
  font-size: 14px;
  outline: none;
  transition:
    border-color 0.2s,
    box-shadow 0.2s;
  appearance: none;
  -webkit-appearance: none;
}
input[type="text"]:focus,
select:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(200, 255, 0, 0.12);
}
input::placeholder {
  color: var(--muted);
}
.select-wrap {
  position: relative;
}
.select-chevron {
  position: absolute;
  right: 14px;
  top: 50%;
  transform: translateY(-50%);
  width: 16px;
  height: 16px;
  color: var(--muted);
  pointer-events: none;
}

/* ─── PARAM ROWS ──────────────────────────────────── */
.param-row {
  display: flex;
  gap: 10px;
  align-items: center;
  margin-bottom: 10px;
  animation: riseIn 0.2s ease both;
}
.param-row .select-wrap {
  flex: 1;
  min-width: 0;
}
.param-row input[type="text"] {
  flex: 2;
  min-width: 0;
}

.btn-remove {
  width: 42px;
  min-width: 42px;
  height: 42px;
  border-radius: var(--r);
  background: transparent;
  border: 1px solid var(--border);
  color: var(--muted);
  font-size: 22px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  margin-top: 0;
  padding: 0;
  line-height: 1;
}
.btn-remove:hover {
  background: rgba(255, 60, 60, 0.1);
  border-color: var(--danger);
  color: var(--danger);
}

/* ─── BUTTONS ─────────────────────────────────────── */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border: none;
  border-radius: var(--r);
  font-family: var(--mono);
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  cursor: pointer;
  transition: all 0.2s;
  width: auto;
  margin-top: 0;
}
.btn svg {
  width: 15px;
  height: 15px;
  flex-shrink: 0;
}

.btn-primary {
  background: var(--accent);
  color: var(--bg);
  font-weight: 700;
}
.btn-primary:hover {
  background: #d8ff22;
  box-shadow: 0 0 24px rgba(200, 255, 0, 0.4);
  transform: translateY(-1px);
}
.btn-ghost {
  background: var(--surface);
  color: var(--text);
  border: 1px solid var(--border);
}
.btn-ghost:hover {
  border-color: var(--accent);
  color: var(--accent);
  background: rgba(200, 255, 0, 0.06);
}
.btn-run {
  width: 100%;
  justify-content: center;
  padding: 20px 32px;
  font-size: 15px;
  font-weight: 700;
  letter-spacing: 0.16em;
  background: var(--accent);
  color: var(--bg);
  border-radius: 10px;
  position: relative;
  overflow: hidden;
}
.btn-run::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 60%;
  height: 100%;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.25),
    transparent
  );
  transform: skewX(-15deg);
  transition: left 0.6s ease;
}
.btn-run:hover::after {
  left: 150%;
}
.btn-run:hover {
  box-shadow:
    0 0 40px rgba(200, 255, 0, 0.4),
    0 4px 20px rgba(0, 0, 0, 0.4);
  transform: translateY(-2px);
}
.btn-run:active {
  transform: translateY(0);
}

.divider {
  height: 1px;
  background: var(--border);
  margin: 28px 0;
}

/* ─── RESULT ──────────────────────────────────────── */
.result-pre {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 24px;
  font-family: var(--mono);
  font-size: 13px;
  line-height: 1.8;
  color: var(--accent);
  min-height: 120px;
  white-space: pre-wrap;
  word-break: break-word;
  margin-bottom: 16px;
}

/* ─── TOAST ───────────────────────────────────────── */
.toast {
  position: fixed;
  bottom: 24px;
  right: 24px;
  background: var(--card);
  border: 1px solid var(--border);
  border-left: 3px solid var(--accent);
  color: var(--text);
  padding: 13px 20px;
  border-radius: var(--r);
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.04em;
  opacity: 0;
  transform: translateY(10px) scale(0.97);
  transition:
    opacity 0.25s,
    transform 0.25s;
  z-index: 9997;
  max-width: calc(100vw - 48px);
}
.toast.show {
  opacity: 1;
  transform: translateY(0) scale(1);
}
.toast.err {
  border-left-color: var(--danger);
  color: #ff9999;
}

/* ─── SCROLLBAR ───────────────────────────────────── */
::-webkit-scrollbar {
  width: 5px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 99px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--accent);
}

