from sklearn.metrics import get_scorer


def evaluate_models(models, X_test, y_test, metric):

    scorer = get_scorer(metric)

    results = []

    for item in models:

        model = item["model"]

        score = scorer(model, X_test, y_test)

        results.append({
            "model": model,
            "params": item["params"],
            "score": score
        })

    return results

def prune_models(
    ranked_models,
    prune_ratio=0.5,
    strategy="ratio",
    threshold=0.9
):

    total_models = len(ranked_models)

    if strategy == "ratio":

        keep_count = max(1, int(total_models * (1 - prune_ratio)))

        return ranked_models[:keep_count]


    elif strategy == "adaptive":

        best_score = ranked_models[0]["score"]

        cutoff = best_score * threshold

        selected = [
            model for model in ranked_models
            if model["score"] >= cutoff
        ]

        # SAFETY: ensure at least one model
        if len(selected) == 0:
            selected = [ranked_models[0]]

        return selected


    else:
        raise ValueError("Invalid pruning strategy")

def generate_summary(best_model, total_models, pruned_models, time_taken):

    return {
        "best_params": best_model["params"],
        "best_score": best_model["score"],
        "models_tested": total_models,
        "models_pruned": pruned_models,
        "time_taken": time_taken
    }

import time


class Timer:

    def __init__(self):
        self.start_time = None

    def start(self):
        self.start_time = time.time()

    def stop(self):
        return time.time() - self.start_time
